"use client";

import { useEffect } from "react";
import { useLedgerStore, SECTION_TYPES } from "@/store/useLedgerStore";
import { Eyebrow } from "@/components/Eyebrow";
import { Hero } from "@/components/Hero";
import { Tabs } from "@/components/Tabs";
import { SectionBlock } from "@/components/SectionBlock";
import { Footer } from "@/components/Footer";

export default function Home() {
  const isHydrated = useLedgerStore((state) => state.isHydrated);
  const activeTab = useLedgerStore((state) => state.activeTab);
  const hydrate = useLedgerStore((state) => state.hydrate);

  useEffect(() => {
    hydrate();
  }, [hydrate]);

  if (!isHydrated) {
    return (
      <main className="max-w-3xl mx-auto w-full px-4 py-8 flex flex-col min-h-screen">
        <Eyebrow />
        <div className="flex-1 flex items-center justify-center font-mono text-[13px] text-gray animate-pulse">
          Loading ledger...
        </div>
        <Footer />
      </main>
    );
  }

  const visibleSections =
    activeTab === "All" ? SECTION_TYPES : SECTION_TYPES.filter((s) => s === activeTab);

  return (
    <main className="max-w-3xl mx-auto w-full px-4 py-8 flex flex-col min-h-screen">
      <Eyebrow />
      <Hero />
      <Tabs />
      <div className="flex-1">
        {visibleSections.map((section) => (
          <SectionBlock key={section} section={section} />
        ))}
      </div>
      <Footer />
    </main>
  );
}
