"use client";

import { useLedgerStore, SECTION_TYPES, SectionType } from "@/store/useLedgerStore";

export function Tabs() {
  const activeTab = useLedgerStore((state) => state.activeTab);
  const setActiveTab = useLedgerStore((state) => state.setActiveTab);

  const tabs: Array<"All" | SectionType> = ["All", ...SECTION_TYPES];

  return (
    <nav className="flex items-center gap-6 border-b border-line mb-8 overflow-x-auto scrollbar-none">
      {tabs.map((tab) => {
        const isActive = activeTab === tab;
        return (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`font-mono uppercase text-[12px] pb-2 px-1 transition-colors whitespace-nowrap -mb-[1px] border-b-2 ${
              isActive
                ? "text-ink font-bold border-gold"
                : "text-gray font-normal border-transparent hover:text-ink"
            }`}
          >
            {tab}
          </button>
        );
      })}
    </nav>
  );
}
