"use client";

import { useLedgerStore } from "@/store/useLedgerStore";

export function Eyebrow() {
  const isHydrated = useLedgerStore((state) => state.isHydrated);

  const dateStr = isHydrated
    ? new Date()
        .toLocaleDateString("en-IN", {
          day: "2-digit",
          month: "short",
          year: "numeric",
        })
        .toUpperCase()
    : "";

  return (
    <header className="flex justify-between items-center border-b border-line pb-3 mb-7 font-mono uppercase text-[11px] text-gray tracking-wider">
      <span>Net Worth Ledger</span>
      <span>{dateStr}</span>
    </header>
  );
}
