"use client";

import { useState } from "react";
import { useLedgerStore, SectionType, formatIndianCurrency } from "@/store/useLedgerStore";

interface SectionBlockProps {
  section: SectionType;
}

export function SectionBlock({ section }: SectionBlockProps) {
  const [name, setName] = useState("");
  const [amount, setAmount] = useState("");

  const allEntries = useLedgerStore((state) => state.entries);
  const addEntry = useLedgerStore((state) => state.addEntry);
  const deleteEntry = useLedgerStore((state) => state.deleteEntry);

  const entries = allEntries.filter((e) => e.section === section);
  const subtotal = entries.reduce((sum, entry) => sum + entry.amount, 0);

  const isLiability = section === "Liabilities";
  const formattedSubtotal = formatIndianCurrency(
    isLiability && subtotal > 0 ? -subtotal : subtotal,
    true
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name.trim() || isNaN(numAmount) || numAmount <= 0) {
      return; // ignore silently as per specification
    }
    addEntry(section, name, numAmount);
    setName("");
    setAmount("");
  };

  return (
    <div className="mb-12">
      {/* Header row */}
      <div className="flex justify-between items-center border-b border-ink pb-2 mb-2">
        <h2 className="font-mono uppercase text-[12px] font-bold text-ink">
          {section}
        </h2>
        <span
          className={`font-mono text-[14px] font-bold ${
            isLiability ? "text-red" : "text-green"
          }`}
        >
          {formattedSubtotal}
        </span>
      </div>

      {/* Entries list */}
      <div className="divide-y divide-line">
        {entries.length === 0 ? (
          <div className="py-8 text-center italic text-gray text-[13px] border-b border-line">
            No entries yet — add one below.
          </div>
        ) : (
          entries.map((entry) => {
            const formattedDate = new Date(entry.timestamp).toLocaleDateString(
              "en-IN",
              {
                day: "2-digit",
                month: "short",
                year: "numeric",
              }
            );
            return (
              <div
                key={entry.id}
                className="grid grid-cols-[1fr_auto_auto] sm:grid-cols-[1fr_120px_auto_auto] items-center gap-3 py-2.5 hover:bg-paper-dim/30 transition-colors px-1"
              >
                <div className="font-sans font-medium text-[14px] text-ink truncate">
                  {entry.name}
                </div>
                <div className="font-mono text-[10px] text-gray hidden sm:block">
                  {formattedDate}
                </div>
                <div
                  className={`font-mono font-bold text-right text-[14px] ${
                    isLiability ? "text-red" : "text-green"
                  }`}
                >
                  {formatIndianCurrency(entry.amount)}
                </div>
                <button
                  onClick={() => deleteEntry(entry.id)}
                  title="Delete entry"
                  className="text-gray hover:text-red hover:bg-red-soft w-6 h-6 flex items-center justify-center rounded-[5px] transition-colors text-[12px] cursor-pointer"
                >
                  ✕
                </button>
              </div>
            );
          })
        )}
      </div>

      {/* Add entry form */}
      <form
        onSubmit={handleSubmit}
        className="mt-4 grid grid-cols-1 sm:grid-cols-[1fr_160px_100px] gap-2 pt-1"
      >
        <input
          type="text"
          placeholder="Add new entry..."
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="bg-paper-dim border border-line rounded-[5px] px-3 py-2 text-[13px] font-sans text-ink placeholder:text-gray focus:outline-none focus:border-gold transition-colors"
        />
        <input
          type="number"
          placeholder="Amount (₹)..."
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          className="bg-paper-dim border border-line rounded-[5px] px-3 py-2 text-[13px] font-mono text-ink placeholder:text-gray focus:outline-none focus:border-gold transition-colors"
        />
        <button
          type="submit"
          className="bg-ink text-paper font-mono font-bold text-[12px] py-2 px-4 rounded-[5px] hover:opacity-90 transition-opacity flex items-center justify-center cursor-pointer"
        >
          + Add
        </button>
      </form>
    </div>
  );
}
