"use client";

import { useLedgerStore, formatIndianCurrency } from "@/store/useLedgerStore";
import { motion, AnimatePresence } from "framer-motion";

export function Hero() {
  const entries = useLedgerStore((state) => state.entries);

  let assets = 0;
  let liabilities = 0;
  entries.forEach((entry) => {
    if (entry.section === "Liabilities") {
      liabilities += entry.amount;
    } else {
      assets += entry.amount;
    }
  });
  const netWorth = assets - liabilities;
  const count = entries.length;

  const formattedNetWorth = formatIndianCurrency(netWorth, true);

  return (
    <section className="mb-10">
      <div className="text-[13px] text-gray font-sans mb-1 tracking-wide">
        Total net worth
      </div>
      <div
        className={`text-[clamp(40px,6vw+1rem,64px)] font-mono font-bold leading-tight select-none flex items-center ${
          netWorth >= 0 ? "text-green" : "text-red"
        }`}
      >
        <span className="inline-flex overflow-hidden py-1">
          {formattedNetWorth.split("").map((char, idx) => (
            <AnimatePresence mode="popLayout" key={idx}>
              <motion.span
                key={`${char}-${idx}`}
                initial={{ y: 25, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: -25, opacity: 0 }}
                transition={{ duration: 0.25, type: "tween", ease: "easeInOut" }}
                className="inline-block"
              >
                {char}
              </motion.span>
            </AnimatePresence>
          ))}
        </span>
      </div>
      <div className="font-mono text-[13px] text-gray mt-2 flex flex-wrap items-center gap-2">
        <span>
          Assets:{" "}
          <strong className="text-green font-bold">
            {formatIndianCurrency(assets)}
          </strong>
        </span>
        <span>·</span>
        <span>
          Liabilities:{" "}
          <strong className="text-red font-bold">
            {formatIndianCurrency(liabilities)}
          </strong>
        </span>
        <span>·</span>
        <span>
          {count} {count === 1 ? "entry" : "entries"}
        </span>
      </div>
    </section>
  );
}
